const staticData = $getWorkflowStaticData('global');
const body = $input.first().json.body || $input.first().json;
const phone = String(body.phone || '').replace(/[^0-9]/g, '');
const digits = phone.length === 11 && phone.startsWith('1') ? phone.slice(1) : phone;
if (digits.length === 10) {
  if (!staticData.whatsappMessaged) staticData.whatsappMessaged = {};
  staticData.whatsappMessaged[digits] = { opted_out: true, at: new Date().toISOString() };
}
return [{ json: { ok: true, phone: digits } }];

const staticData = $getWorkflowStaticData('global');
const cfg = staticData.config || {};

const CITIES = cfg.cities || [
  'Savannah GA','Atlanta GA','Charlotte NC','Nashville TN','Memphis TN',
  'Jacksonville FL','Orlando FL','Tampa FL','Miami FL','Houston TX',
  'Laredo TX','Lubbock TX','Corpus Christi TX','Little Rock AR','Wichita KS',
  'Baton Rouge LA','Huntsville AL','Mobile AL','Fayetteville NC','Greenville SC'
];
const INDUSTRIES = cfg.industries || [
  'electrician','plumber','HVAC contractor','roofer','landscaper',
  'painter','handyman','cleaning service','pest control','concrete contractor',
  'fence contractor','tile installer','tree service','pool service','garage door repair'
];
const maxMsg = cfg.max_whatsapp || 25;

const combos = [];
const used = new Set();
while (combos.length < 8 && combos.length < CITIES.length * INDUSTRIES.length) {
  const c = CITIES[Math.floor(Math.random() * CITIES.length)];
  const i = INDUSTRIES[Math.floor(Math.random() * INDUSTRIES.length)];
  const key = c + '|' + i;
  if (!used.has(key)) { used.add(key); combos.push({city: c, industry: i}); }
}

return combos.map(x => ({ json: { ...x, max_messages: maxMsg } }));

const results = [];
for (const item of $input.all()) {
  const places = item.json.places || [];
  const prevNode = $('Set Config & Target');
  const industry = prevNode.first ? prevNode.first().json.industry : '';
  const city = prevNode.first ? prevNode.first().json.city : '';
  for (const p of places) {
    if (p.websiteUri) continue;
    const phone = p.nationalPhoneNumber || '';
    if (!phone) continue;
    results.push({ json: {
      business_name: p.displayName?.text || '',
      phone,
      industry,
      city,
      rating: p.rating || 0,
      reviews_count: p.userRatingCount || 0,
      place_id: p.id || '',
      address: p.formattedAddress || ''
    }});
    if (results.length >= 5) break;
  }
  if (results.length >= 5) break;
}
return results;

const staticData = $getWorkflowStaticData('global');
if (!staticData.whatsappMessaged) staticData.whatsappMessaged = {};

const out = [];
const maxMsg = 25;

for (const item of $input.all()) {
  const l = item.json;
  let digits = String(l.phone || '').replace(/[^0-9]/g, '');
  if (digits.length === 11 && digits.startsWith('1')) digits = digits.slice(1);
  if (digits.length !== 10) continue;
  if (staticData.whatsappMessaged[digits]) continue;
  if (out.length >= maxMsg) break;
  out.push({ json: { ...l, phone_digits: digits } });
}
return out;

const l = $input.first().json;

// WhatsApp API needs number in international format without +
// Egyptian recipient US numbers: 1 + 10 digits
const wa_to = '1' + l.phone_digits;

// business_name used as {{1}} template variable
const business_name = l.business_name || 'there';

return [{ json: { ...l, wa_to, business_name } }];

