const staticData = $getWorkflowStaticData('global');
const l = $('Generate Preview & Message').first().json;
const today = new Date().toISOString().slice(0,10);
const digits = l.phone_digits;

if (!staticData.whatsappMessaged) staticData.whatsappMessaged = {};
staticData.whatsappMessaged[digits] = { at: new Date().toISOString(), name: l.business_name };

if (!staticData.waLeads) staticData.waLeads = [];
staticData.waLeads.push({
  business_name: l.business_name,
  phone: l.phone,
  phone_digits: digits,
  industry: l.industry,
  city: l.city,
  status: 'sent',
  sent_at: new Date().toISOString()
});
if (staticData.waLeads.length > 500) staticData.waLeads = staticData.waLeads.slice(-500);

if (!staticData.waDailyCosts) staticData.waDailyCosts = {};
if (!staticData.waDailyCosts[today]) staticData.waDailyCosts[today] = {count: 0, cost: 0};
staticData.waDailyCosts[today].count++;
staticData.waDailyCosts[today].cost = parseFloat((staticData.waDailyCosts[today].count * 0.025).toFixed(4));

return [{ json: { ...l, saved: true } }];

const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0,10);
const dayData = (staticData.waDailyCosts || {})[today] || {count:0, cost:0};
const sent = $input.all();

let text = 'WHATSAPP OUTREACH ABGESCHLOSSEN\n\n';
text += 'Heute gesendet: ' + dayData.count + ' Nachrichten\n';
text += 'Kosten heute: $' + dayData.cost.toFixed(4) + '\n\n';

if (sent.length > 0) {
  text += 'Diese Runde:\n';
  sent.forEach(s => {
    const l = s.json;
    text += '  - ' + (l.business_name||'?') + ' (' + (l.city||'') + ')\n';
  });
}

return [{ json: { report_text: text } }];
